const body = $input.item.json.body;
const productos = (body.productos || [])
  .map(p => {
    const combo = p.combinacion ? ` (${p.combinacion})` : '';
    return `<li><strong>${p.nombre}${combo}</strong> — Ref: ${p.referencia}</li>`;
  }).join('');
return [{json: {
  fecha: body.fecha || new Date().toLocaleDateString('es-ES'),
  total: body.total || (body.productos || []).length,
  productos_html: `<ul>${productos}</ul>`
}}];
